    }
    written += len;

    if (label_count > 0) {
        // Append opening brace for labels
        len = snprintf(metric_output + written, SIZE_MAX, "{");
        if (len < 0 || len >= SIZE_MAX) {
            return -1;
        }
        written += len;

        for (int i = 0; i < label_count; i++) {
